WebLink.url:
{!REQUIRESCRIPT("/soap/ajax/30.0/connection.js")}

if (confirm("Do you really want to override the existing location address of the contact?"))
{
	var fieldsNeedToBeCopied = ["LocationAddressLine2__c", "LocationAddressLine3__c", "LocationCity__c",  "LocationCountry__c", "LocationPoBox__c",	"LocationState__c", "LocationStreetNr__c", "LocationZip__c"];

    // identify the record
    var contact = new sforce.SObject("Contact");
    contact.id = "{!Contact.Id}";

    var results = sforce.connection.query("SELECT Name, LocationAddressLine2__c, LocationAddressLine3__c, LocationCity__c, LocationCountry__c, LocationPoBox__c, LocationState__c, LocationStreetNr__c, LocationZip__c FROM Account WHERE Id = '{!Account.Id}' LIMIT 1");

	var account = results.getArray("records")[0];
	for (i = 0; i < fieldsNeedToBeCopied.length; i++)
	{
		contact[fieldsNeedToBeCopied[i]] = account[fieldsNeedToBeCopied[i]];
	}

    // save the change
    sforce.connection.update([contact]);

    //refresh the page
    window.location.reload();
}
